import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  SearchTextInput,
  Select,
  dispatchAppToast,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { EmployeeDto, UpdateEmployeeDto } from '../../../services/ns/models';
import { nhanVienPageLabels as labels } from '../../../constants/nhanVienPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import {
  getErpListRowMenuHint,
  catalogListRowMenuHintDismissStorageKey,
} from '../../../utils/catalogListRowMenuHint';
import { useCatalogListPermissions } from '../../../hooks/useCatalogListPermissions';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import {
  CatalogListMasterLinPageLayout,
  CatalogRowActionMenu,
  useCatalogListPaging,
  useCatalogTableBusy,
  type CatalogBatchDeleteMode,
  type CatalogListToolbarBridge,
  type CatalogRowMenuAction,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
} from '../../../components/catalog/catalogUiSchema';
import { hrCatalogDocumentTypes } from '../../../config/documentHistoryClients';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-nhan-vien';
const PAGE_ID = 'ns-nhan-vien';
const CATALOG_KIND = 'hr-employees';

const TYPE_OPTIONS = [
  { value: '', label: 'Tất cả loại HĐ' },
  { value: 'TimeContract', label: 'Thời gian' },
  { value: 'PieceRate', label: 'Khoán' },
  { value: 'Seasonal', label: 'Thời vụ' },
];

const ACTIVE_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: 'true', label: 'Hoạt động' },
  { value: 'false', label: 'Nghỉ việc' },
];

type EmployeeListRow = EmployeeDto & { name: string };

function toUpdateDto(row: EmployeeDto, isActive: boolean): UpdateEmployeeDto {
  return {
    fullName: row.fullName,
    type: row.type,
    departmentId: row.departmentId,
    teamId: row.teamId,
    phone: row.phone,
    email: row.email,
    position: row.position,
    baseSalary: row.baseSalary,
    joinDate: row.joinDate,
    legacyCode: row.legacyCode,
    isActive,
  };
}

const NhanVienListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const { canWrite } = useCatalogListPermissions(CATALOG_KIND);
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [reloadKey, setReloadKey] = useState(0);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [type, setType] = useState('');
  const [activeFilter, setActiveFilter] = useState('');
  const [items, setItems] = useState<EmployeeDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: EmployeeListRow } | null>(
    null,
  );
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const gridRows = useMemo<EmployeeListRow[]>(
    () => items.map(r => ({ ...r, name: r.fullName })),
    [items],
  );

  const selection = useCatalogListSelection({
    rows: gridRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = useCallback(() => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = useCallback(() => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  }, [pulseSearch, searchDraft, resetPage, selection]);

  const navigateToRow = useCallback(
    (id: string, startInEditMode?: boolean) => {
      navigate(`/ns/nhan-vien/${id}`, {
        state: startInEditMode ? { startInEditMode: true } : undefined,
      });
    },
    [navigate],
  );

  const openView = useCallback(
    (row: EmployeeListRow) => navigateToRow(row.id),
    [navigateToRow],
  );

  const openEdit = useCallback(
    (row: EmployeeListRow) => {
      if (!canWrite) {
        openView(row);
        return;
      }
      navigateToRow(row.id, true);
    },
    [canWrite, navigateToRow, openView],
  );

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService
        .getEmployees({
          search: search || undefined,
          type: type || undefined,
          isActive: activeFilter === '' ? undefined : activeFilter === 'true',
          page,
          pageSize,
        })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [dispatch, search, type, activeFilter, page, pageSize, reloadKey]);

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: EmployeeListRow; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'history':
          toolbarBridgeRef.current?.openHistory();
          break;
        case 'delete':
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.map(r => r.id)
        : [...selection.selectedIds];
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(
        ids.map(id => {
          const row = items.find(r => r.id === id)!;
          return hrService.updateEmployee(id, toUpdateDto(row, false));
        }),
      );
      dispatchAppToast(dispatch, {
        message: `Đã ngưng ${ids.length} nhân viên`,
        type: 'success',
      });
    } else {
      await Promise.all(ids.map(id => hrService.deleteEmployee(id)));
      dispatchAppToast(dispatch, {
        message: `Đã xóa ${ids.length} nhân viên`,
        type: 'success',
      });
    }
    refresh();
  };

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = !!rowMenuRow && canWrite;
  const rowMenuShowView = !!rowMenuRow && !canWrite;

  const rowMenuHintMessage = getErpListRowMenuHint(viewMobile);

  const filterBar = (
    <>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder={labels.searchPlaceholder}
          value={searchDraft}
          onChange={setSearchDraft}
          onSearch={handleSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </div>
      <div className={styles.field} data-testid={`${TEST_ID}-field-type`}>
        <Select
          label="Loại HĐ"
          value={type}
          onChange={e => {
            setType(e.target.value);
            resetPage();
            selection.clearSelection();
            setReloadKey(k => k + 1);
          }}
          options={TYPE_OPTIONS}
          fullWidth
        />
      </div>
      <div className={styles.field} data-testid={`${TEST_ID}-field-active`}>
        <Select
          label="Trạng thái"
          value={activeFilter}
          onChange={e => {
            setActiveFilter(e.target.value);
            resetPage();
            selection.clearSelection();
            setReloadKey(k => k + 1);
          }}
          options={ACTIVE_OPTIONS}
          fullWidth
        />
      </div>
    </>
  );

  return (
    <CatalogListMasterLinPageLayout
      testIdPrefix={TEST_ID}
      pageId={PAGE_ID}
      catalogKind={CATALOG_KIND}
      documentType={hrCatalogDocumentTypes[CATALOG_KIND]}
      selection={selection}
      totalCount={totalCount}
      selectableOnPage={gridRows}
      onAdd={() => navigate('/ns/nhan-vien/them')}
      onEdit={openEdit}
      onRefresh={refresh}
      onBatchDelete={handleBatchDelete}
      showSchemaConfig
      onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
      toolbarBridgeRef={toolbarBridgeRef}
      page={page}
      pageSize={pageSize}
      onPageChange={p => {
        setPage(p);
        selection.clearSelection();
      }}
      onPageSizeChange={setPageSize}
      showTableLoading={showTableLoading}
      header={{
        title: labels.listTitle,
        titleIconClass: 'fas fa-users',
        pageId: PAGE_ID,
      }}
      listTitle={labels.listSubtitle}
      listRowMenuHelp
      filters={filterBar}
      filterMaxWidthPx={1000}
      schemaEditorModal={
        <CatalogUiSchemaEditorModal
          testIdPrefix={TEST_ID}
          catalogKind={CATALOG_KIND}
          isOpen={schemaEditorOpen}
          onClose={() => setSchemaEditorOpen(false)}
          onSaved={() => reloadSchema()}
        />
      }
      extraModals={
        <CatalogRowActionMenu
          open={rowMenu != null}
          x={rowMenu?.x ?? 0}
          y={rowMenu?.y ?? 0}
          onClose={() => setRowMenu(null)}
          onSelect={handleRowMenuSelect}
          testIdPrefix={TEST_ID}
          showEdit={rowMenuShowEdit}
          showView={rowMenuShowView}
          showHistory={!!rowMenuRow}
          showDelete={rowMenuShowEdit}
        />
      }
    >
      {gridRows.length === 0 ? (
        <div className={styles.empty} data-testid={`${TEST_ID}-empty`}>
          <i className="fas fa-inbox" />
          <p>{search.trim() ? 'Không tìm thấy nhân viên phù hợp' : labels.empty}</p>
        </div>
      ) : listColumns.length > 0 ? (
        <CatalogListGridFromSchema
          testIdPrefix={TEST_ID}
          rows={gridRows}
          page={page}
          pageSize={pageSize}
          columns={listColumns}
          schema={schema}
          selection={selection}
          getRowId={r => r.id}
          onRowOpenActionMenu={handleRowOpenActionMenu}
          rowMenuHintMessage={rowMenuHintMessage}
          rowMenuHintDismissStorageKey={catalogListRowMenuHintDismissStorageKey(TEST_ID)}
          enableRowMenuLongPress={viewMobile}
        />
      ) : null}
    </CatalogListMasterLinPageLayout>
  );
};

export default NhanVienListPage;
